import argparse
import json
import os
import numpy as np
import heapq

from cogniplan_env import ExplorationEnv


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n['coords'])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get('coords', nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n['coords'], dtype=float) -
                    np.array(nodes[j]['coords'], dtype=float)
                ))
                if w > 0:
                    adj[i].append((j, w))
    r_idx = N
    adj.append([])
    node_to_nb = {}
    for idx, nb in enumerate(neighbors):
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) - np.array(nb, dtype=float)
        ))
        if w > 0:
            adj[r_idx].append((j, w))
            adj[j].append((r_idx, w))
            node_to_nb[j] = idx
    return adj, coord_to_idx, r_idx, node_to_nb


class SimpleGreedyPlanner:
    def __init__(self, dist_denom=3.6, reverse_penalty=0.3):
        self.dist_denom = float(dist_denom)
        self.reverse_penalty = float(reverse_penalty)
        self.reset()

    def reset(self):
        self.prev_pos = None

    def plan(self, obs):
        robot_pos = np.array(obs['robot_pos'], dtype=float)
        nodes = obs['nodes']
        neighbors = obs['neighbors']

        if not neighbors:
            self.prev_pos = robot_pos
            return None

        adj, coord_to_idx, r_idx, node_to_nb = build_graph(
            nodes, robot_pos, neighbors
        )
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - self.prev_pos
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        candidate_js = [
            j for j in range(N)
            if j in node_to_nb and dist[j] < float('inf')
        ]
        if not candidate_js:
            self.prev_pos = robot_pos
            return tuple(neighbors[0]) if neighbors else None

        primary = [
            j for j in candidate_js
            if float(nodes[j].get('utility', 0.0)) > 0
        ]
        if not primary:
            primary = candidate_js

        node_scores = {}
        for j in primary:
            utility = float(nodes[j].get('utility', 0.0))
            d = dist[j]
            score = utility / (d + self.dist_denom)
            node_scores[j] = score

        nb_scores = {}
        for j, score in node_scores.items():
            idx = node_to_nb.get(j)
            if idx is None:
                continue
            if reverse_idx is not None and idx == reverse_idx:
                score *= (1.0 - self.reverse_penalty)
            if idx not in nb_scores or score > nb_scores[idx]:
                nb_scores[idx] = score

        if not nb_scores:
            self.prev_pos = robot_pos
            return tuple(neighbors[0]) if neighbors else None

        best_idx = max(nb_scores, key=nb_scores.get)
        self.prev_pos = robot_pos.copy()
        return tuple(neighbors[best_idx])


def run_episode(env, planner):
    planner.reset()
    obs = env.reset()
    for _ in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get('done', False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    cfg_path = os.path.join(args.checkpoint, 'planner_cfg.json')
    cfg = {}
    if os.path.exists(cfg_path):
        with open(cfg_path) as f:
            cfg = json.load(f)

    planner = SimpleGreedyPlanner(**cfg)

    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    with open(eval_config_path) as f:
        eval_config = json.load(f)

    map_entries = []
    if 'episodes' in eval_config:
        for ep in eval_config['episodes']:
            map_entries.append({
                'map_path': ep['map_path'],
                'env_type': ep.get('env_type', 'unknown'),
            })
    else:
        maps_dir = os.path.join(args.data_path, 'maps_eval')
        for env_type in ['room', 'tunnel', 'outdoor']:
            d = os.path.join(maps_dir, env_type)
            if not os.path.isdir(d):
                continue
            for fn in sorted(os.listdir(d)):
                if fn.endswith('.png'):
                    map_entries.append({
                        'map_path': os.path.join('maps_eval', env_type, fn),
                        'env_type': env_type,
                    })

    per_episode = []
    per_type = {}
    for entry in map_entries:
        map_path = os.path.join(args.data_path, entry['map_path'])
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get('success', False) else 0
        explored_rate = float(metrics.get('explored_rate', 0.0))
        travel_distance = float(metrics.get('travel_distance', 0.0))

        res = {
            'map_path': entry['map_path'],
            'env_type': entry['env_type'],
            'success': success,
            'travel_distance': travel_distance,
            'explored_rate': explored_rate,
        }
        per_episode.append(res)

        t = entry['env_type']
        if t not in per_type:
            per_type[t] = []
        per_type[t].append(res)

    total_episodes = len(per_episode)
    avg_explored_rate = sum(e['explored_rate'] for e in per_episode) / total_episodes if total_episodes else 0.0
    success_rate = sum(e['success'] for e in per_episode) / total_episodes if total_episodes else 0.0
    succ_dists = [e['travel_distance'] for e in per_episode if e['success']]
    avg_travel_distance = sum(succ_dists) / len(succ_dists) if succ_dists else 0.0

    per_type_out = {}
    for t, episodes in per_type.items():
        n = len(episodes)
        per_type_out[t] = {
            'explored_rate': sum(e['explored_rate'] for e in episodes) / n,
            'success_rate': sum(e['success'] for e in episodes) / n,
            'travel_distance': sum(e['travel_distance'] for e in episodes if e['success']) / sum(1 for e in episodes if e['success']) if any(e['success'] for e in episodes) else 0.0,
        }

    result = {
        'explored_rate': avg_explored_rate,
        'travel_distance': avg_travel_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': total_episodes,
    }

    os.makedirs(os.path.dirname(args.output) or '.', exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)


if __name__ == '__main__':
    main()
